+const fn encode_journal_mode(mode: JournalMode) -> u8 {
+    match mode {
+        JournalMode::Delete => 0,
+        JournalMode::Wal => 1,
+    }
+}
+
+const fn decode_journal_mode(raw: u8) -> JournalMode {
+    match raw {
+        1 => JournalMode::Wal,
+        _ => JournalMode::Delete,
+    }
